public class SummarizeRequest
{
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
}

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that ranks sentences by word-frequency scoring
/// and returns the top-ranked sentences in their original order.
/// </summary>
public class ExtractiveSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "be", "have", "has", "had", "do", "does", "did",
        "will", "would", "could", "should", "may", "might", "shall", "can",
        "not", "no", "so", "if", "as", "its", "he", "she", "they", "we",
        "you", "i", "me", "my", "your", "his", "her", "our", "their", "which",
        "who", "whom", "what", "where", "when", "how", "all", "each", "every",
        "both", "few", "more", "most", "other", "some", "such", "than", "too",
        "very", "just", "about", "above", "after", "again", "also", "am", "an",
        "any", "because", "been", "before", "being", "between", "during", "into",
        "only", "own", "same", "then", "there", "these", "those", "through",
        "under", "until", "up", "while"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scoredSentences);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return text
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .Select(s => s + ".")
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
                }
            }
        }

        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = GetWords(sentence);
        if (words.Length == 0) return 0;

        double score = words
            .Where(w => wordFrequencies.ContainsKey(w))
            .Sum(w => wordFrequencies[w]);

        // Normalize by sentence length to avoid bias toward longer sentences
        return score / words.Length;
    }

    private static string[] GetWords(string text)
    {
        return text
            .Split([' ', '\t', '\n', '\r', ',', ';', ':', '"', '\'', '(', ')', '[', ']', '{', '}'],
                StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.Trim('.', '!', '?'))
            .Where(w => w.Length > 0)
            .ToArray();
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText must not be empty.");

        if (request.MaxSentences < 1)
            return BadRequest("MaxSentences must be at least 1.");

        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

